
.character-panel {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.char-row {
  background: rgba(255,255,255,0.03);
  border-radius: 6px;
  padding: 8px 10px;
}

.char-header {
  display: flex;
  justify-content: space-between;
  margin-bottom: 4px;

  .char-name { font-size: 13px; color: #d0d0e0; font-weight: bold; }
  .char-role { font-size: 11px; color: #666688; }
}

.affection-bar {
  height: 4px;
  background: #2a2a4a;
  border-radius: 2px;
  overflow: hidden;
  margin: 4px 0;
}

.affection-fill {
  height: 100%;
  border-radius: 2px;
  transition: width 0.5s;
}

.char-meta {
  display: flex;
  justify-content: space-between;
  font-size: 11px;

  .affection-text { color: #8888aa; }
  .sq-status { color: #8888aa; }
  .sq-done { color: #81c784; margin-left: 2px; }
  .sq-pending { color: #555577; margin-left: 2px; }
}
