
.tab-nav {
  display: flex;
  border-bottom: 1px solid #3d3d5c;
  background: #16213e;
}

.tab-btn {
  flex: 1;
  padding: 8px 12px;
  background: none;
  border: none;
  color: #8888aa;
  cursor: pointer;
  font-size: 13px;
  transition: all 0.2s;
  border-bottom: 2px solid transparent;

  &:hover {
    color: #c0c0e0;
    background: rgba(255,255,255,0.05);
  }

  &.active {
    color: #ffcc80;
    border-bottom-color: #ffcc80;
  }
}
