
.card {
  width: 100%;
  max-width: 720px;
  background-color: #1a1a2e;
  border: 1px solid #3d3d5c;
  border-radius: 8px;
  display: flex;
  flex-direction: column;
  font-size: 13px;
  line-height: 1.35;
  margin: 0 auto;
  color: #d0d0e0;
  overflow: hidden;
}

.content-area {
  padding: 12px;
  min-height: 0;
}

.tab-pane {
  display: none;
  animation: fadeEffect 0.3s;
}

.tab-pane.active {
  display: block;
}

@keyframes fadeEffect {
  from { opacity: 0; transform: translateY(5px); }
  to { opacity: 1; transform: translateY(0); }
}
