
.quest-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.section {
  background: rgba(255,255,255,0.03);
  border-radius: 6px;
  padding: 10px;
}

.section-title {
  font-weight: bold;
  margin-bottom: 8px;
  color: #ffcc80;
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 1px;
}

.info-row {
  display: flex;
  justify-content: space-between;
  padding: 3px 0;
  font-size: 12px;

  .label { color: #8888aa; }
  .value { color: #d0d0e0; }
  .route-a { color: #81c784; }
  .route-b { color: #ef5350; }
}

.empty {
  color: #666688;
  font-style: italic;
  font-size: 12px;
}

.task-item {
  padding: 4px 0;
  border-bottom: 1px solid rgba(255,255,255,0.05);

  .task-name { font-size: 12px; color: #c0c0e0; }
  .task-desc { font-size: 11px; color: #8888aa; }
}
